-- Program: Skinny Fat Advanced Shred
-- Category: Body-Specific -> body_specific
-- Priority: high
-- Durations: [8, 12, 16], Sessions: [5, 6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Skinny Fat Advanced Shred',
    'Aggressive body recomposition program for the skinny-fat physique. Combines heavy compound lifting for muscle preservation with strategic HIIT and LISS cardio for fat loss. Push/Pull/Legs split with upper body power day and conditioning.',
    'body_specific',
    'advanced',
    16,
    6,
    'full_body',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Skinny Fat Advanced Shred - 8w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Hard',
    8,
    'Skinny Fat Advanced Shred - 8w 5x/wk',
    'body_specific',
    5,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Skinny Fat Advanced Shred'
ON CONFLICT DO NOTHING;

